      "inherentSkills": [
        {
          "name": "Remember My Name",
          "description": "After dashing for 2.5s, Lupa enters Sprint state. The next <color=Highlight>Basic Attack</color> is replaced with <color=Highlight>Basic Attack - Starfall</color>.\nGain increased resistance to interruptions while casting <color=Highlight>Heavy Attack - Wolf's Gnawing</color>, <color=Highlight>Heavy Attack - Wolf's Claw</color>, and <color=Highlight>Mid-air Attack - Firestrike</color>.",
          "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Atlas/SkillIcon/SkillIconLupa/SP_IconLupaD1.webp"
        },
        {
          "name": "Applause of Victory",
          "description": "Defeating a <color=Highlight>marked</color> target resets the cooldown of Resonance Skill <color=Highlight>Shewolf's Hunt</color>.\n\n<size=40><color=Title>Resonance Liberation - Glory</color></size>\nCasting Resonance Liberation <color=Highlight>Fire-Kissed Glory</color> grants <color=Highlight>Glory</color>. Within 35s:\nAttacks of all Resonators in the team ignore 3% of the target's Fusion RES. For each Fusion Resonator in the team other than Lupa, this effect increases by 3%, up to the maximum of 9%. When there are 3 Fusion Resonators in the team, Resonators' attacks further ignore 6% Fusion RES.",
          "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Atlas/SkillIcon/SkillIconLupa/SP_IconLupaD2.webp"
        }
      ],
