    "sequenceIcons": [
      {
        "sequence": 1,
        "name": "The Gleam Meant for Radiance",
        "description": "The DMG Multipliers of <color=Highlight>Basic Attack - Elucidated</color>, <color=Highlight>Dodge Counter - Decipher</color>, <color=Highlight>Resonance Skill - BIG BOOMY BOOM!</color>, and <color=Highlight>Resonance Skill - Soliskin to the Aid</color> are increased by 70%.\nSigrika becomes immune to interruptions while casting <color=Highlight>Basic Attack - Elucidated</color>, <color=Highlight>Resonance Skill - BIG BOOMY BOOM!</color>, and <color=Highlight>Resonance Skill - Soliskin to the Aid</color>.\n<color=Highlight><te href=141208>Encapsulated</te></color> now stacks up to 3 times. After casting Outro Skill <color=Highlight>In This Very Moment</color>, Sigrika obtains <SapTag=2>1</SapTag> additional {Cus:Sap,S=stack P=stacks SapTag=2}.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM1_UI.webp"
      },
      {
        "sequence": 2,
        "name": "The Bitterness Steeped in Hope",
        "description": "The DMG Multiplier of <color=Highlight>Forte Circuit - Learn My True Name</color> is increased by 120%. \nWhen not in combat for over 4s, Sigrika gains <color=Highlight><te href=141204>Divergent</te></color>. This effect is active for up to <SapTag=3>1</SapTag> {Cus:Sap,S=time P=times SapTag=3} every 4s.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM2_UI.webp"
      },
      {
        "sequence": 3,
        "name": "I Flee, Yet I Seek",
        "description": "<color=Highlight><te href=141203>Innate Gift?</te></color> now stacks up to 4 times and is no longer removed after Sigrika casts <color=Highlight>Forte Circuit - Learn My True Name</color> or is switched off the field.\nWhen not in combat, all <color=Highlight><te href=141203>Innate Gift?</te></color> stacks are removed every 30s.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM6_UI.webp"
      },
      {
        "sequence": 4,
        "name": "I Lose, Yet I Gain",
        "description": "When a Resonator in the team casts Echo Skill, all Resonators in the team gain an 20% ATK increase for 20s.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM4_UI.webp"
      },
      {
        "sequence": 5,
        "name": "Until Submerged by the Dark",
        "description": "The DMG Multiplier of Resonance Liberation <color=Highlight>Where Trust Leads Me!</color> is increased by 30%.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM5_UI.webp"
      },
      {
        "sequence": 6,
        "name": "True Names Resurfaced, Rising in Light",
        "description": "Targets take 30% more DMG from Sigrika.\n<color=Highlight><te href=141203>Innate Gift?</te></color> gains following effects:\n- Each stack additionally grants <color=Highlight>Runic Outburst</color>, <color=Highlight>Runic Chain Whip</color>, <color=Highlight>Runic Soliskin</color>, and <color=Highlight>Forte Circuit - Learn My True Name</color> 15% DMG Amplification, up to 60%.\n- Each stack causes <color=Highlight>Runic Outburst</color>, <color=Highlight>Runic Chain Whip</color>, <color=Highlight>Runic Soliskin</color>, and <color=Highlight>Forte Circuit - Learn My True Name</color> to ignore 7.5% of the target's DEF when dealing damage, up to 30%.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_XigelikaM3_UI.webp"
      }
    ],
