    "sequenceIcons": [
      {
        "sequence": 1,
        "name": "When the Alarm Clock Rings",
        "description": "Casting <color=Highlight>Targeted Action</color> or <color=Highlight>Forcible Riposte</color> gives a 50% Spectro DMG Bonus for 14s.\nResonance Skill <color=Highlight>Heavy Slash - Nightfall</color> can't be interrupted.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM1_UI.webp"
      },
      {
        "sequence": 2,
        "name": "Stale Bread With Energy Drink",
        "description": "Crit. Rate is increased by 20%.\nThe DMG Multiplier of <color=Highlight>Targeted Action</color> and <color=Highlight>Forcible Riposte</color> is increased by 80%.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM2_UI.webp"
      },
      {
        "sequence": 3,
        "name": "Each Day A New Commute",
        "description": "When in <color=Highlight><te href=850064>Inferno Mode</te></color>, every 1 <te href=850065>Blazes</te> consumed increases the last stage DMG Multiplier of the subsequent Resonance Liberation <color=Highlight>The Last Stand</color> by 8%, maxed at 1200%.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM3_UI.webp"
      },
      {
        "sequence": 4,
        "name": "More Efficiency, Less Drama",
        "description": "When Intro Skill <color=Highlight>Immediate Execution</color> is cast, the ATK of all Resonators in the team is increased by 20% for 30s.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM4_UI.webp"
      },
      {
        "sequence": 5,
        "name": "Delivered In Full On Time",
        "description": "The DMG Multiplier of Resonance Liberation <color=Highlight>Rekindle</color> is increased by 120%.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM5_UI.webp"
      },
      {
        "sequence": 6,
        "name": "First Things First? Clock Out!",
        "description": "The DMG Multipliers of <color=Highlight>Heavy Slash - Daybreak</color>, <color=Highlight>Heavy Slash- Dawning</color>, <color=Highlight>Heavy Slash - Nightfall</color>, and <color=Highlight>Heavy Slash - Lightsmash</color> are increased by 40%. Every <te href=850065>Blaze</te> consumed increases the DMG Multiplier of <color=Highlight>Heavy Slash - Nightfall</color> by 40% on hit.\nGain following effects when in <color=Highlight><te href=850064>Inferno Mode</te></color>: \n- When Blaze is lower than 70, restore 70 Blazes immediately. This effect is triggered once in <color=Highlight>Inferno Mode</color>.\n- Within 8s after entering <color=Highlight>Inferno Mode</color>, Zani will remain standing with at least 1 HP if hit by a fatal blow.",
        "iconSourceUrl": "https://static.nanoka.cc/assets/ww/UIResources/Common/Image/IconDevice/T_IconDevice_ZanniM6_UI.webp"
      }
    ],
